// Termin-Datensatz aus dem Notion Get-Page-Response extrahieren.
// Voraussetzung: vorheriger Notion-Node mit "Simplify Output = false".
const page = $input.first().json;
const props = page.properties || {};

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(r => r.plain_text).join('');
  if (prop.type === 'title')     return (prop.title || []).map(r => r.plain_text).join('');
  if (prop.type === 'url')       return prop.url || '';
  if (prop.type === 'checkbox')  return !!prop.checkbox;
  if (prop.type === 'select')    return prop.select?.name || '';
  if (prop.type === 'date')      return prop.date?.start || '';
  return '';
}

return [{
  json: {
    page_id:              page.id,
    ort_name:             getText(props['Ort Name']),
    ort_adresse:          getText(props['Ort Adresse']),
    gast_name:            getText(props['Gast Name']),
    gast_web:             getText(props['Gast Web']),
    gastvortrag_name:     getText(props['Gastvortrag Name']),
    gastvortrag_web:      getText(props['Gastvortrag Web']),
    themenvorschau:       getText(props['Themenvorschau']),
    naechste_termine_raw: getText(props['Nächste Termine']),
    status:               getText(props['Status']),
    // Roh-Datum für die Formatierung im Aufbereiten-Node
    datum_start:          props['Datum']?.date?.start || '',
    datum_end:            props['Datum']?.date?.end || '',
  }
}];

// Zentraler Aufbereiten-Node: baut den generate-agenda.js Payload
// sowie ein fertig ge-escaptes Shell-Kommando.
const termin_data = $('Code: Termin extrahieren').first().json;
const tops_raw    = $('Notion: TOPs laden').all().map(i => i.json);
const sub_raw_all = $('Notion: Fallgeber laden').all().map(i => i.json);
const members_raw = $('Notion: Mitglieder laden').all().map(i => i.json);

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(r => r.plain_text).join('') || '';
  if (prop.type === 'title')     return (prop.title || []).map(r => r.plain_text).join('') || '';
  if (prop.type === 'url')       return prop.url || '';
  if (prop.type === 'checkbox')  return !!prop.checkbox;
  if (prop.type === 'number')    return prop.number ?? 0;
  if (prop.type === 'select')    return prop.select?.name || '';
  return '';
}

// ── Datum formatieren ──────────────────────────────────────────────
function formatTermin(raw_start, raw_end) {
  if (!raw_start) return '';
  const start = new Date(raw_start);
  const dateStr = start.toLocaleDateString('de-DE', { day:'2-digit', month:'2-digit', year:'numeric' });
  const startTime = start.toLocaleTimeString('de-DE', { hour:'2-digit', minute:'2-digit' });
  if (raw_end) {
    const end = new Date(raw_end);
    const endTime = end.toLocaleTimeString('de-DE', { hour:'2-digit', minute:'2-digit' });
    return `${dateStr}, ${startTime} – ${endTime} Uhr`;
  }
  return `${dateStr}, ${startTime} Uhr`;
}
const termin_str  = formatTermin(termin_data.datum_start, termin_data.datum_end);
const datei_datum = termin_data.datum_start
  ? new Date(termin_data.datum_start).toISOString().slice(0, 10)
  : 'unbekannt';

// ── Mitglieder ─────────────────────────────────────────────────────
const mitglieder = members_raw.map(m => ({
  name:  getText(m.properties?.['Name']),
  firma: getText(m.properties?.['Firma']),
  web:   getText(m.properties?.['Web']),
}));

// ── TOPs + Fallgeber (Sub-Items) ───────────────────────────────────
const tops = tops_raw.map(t => {
  const top_id = t.id;
  const props  = t.properties;

  const sub_items = sub_raw_all
    .filter(s => (s.properties?.['Eltern-TOP']?.relation || []).some(r => r.id === top_id))
    .sort((a, b) => (getText(a.properties?.['Reihenfolge']) || 0) - (getText(b.properties?.['Reihenfolge']) || 0))
    .map((s, idx) => ({
      nr:               idx + 1,
      fallgeber:        getText(s.properties?.['Fallgeber Name']),
      sub_zeit:         getText(s.properties?.['Sub Zeit']),
      sub_beschreibung: getText(s.properties?.['Sub Beschreibung']),
    }));

  return {
    titel:        getText(props?.['Titel']),
    zeit:         getText(props?.['Zeit']),
    beschreibung: getText(props?.['Beschreibung']),
    untertitel:   getText(props?.['Untertitel']),
    sub_items,
  };
});

// Sortierung der TOPs nach Reihenfolge (Notion-Sort als Fallback abgesichert)
tops_raw.forEach((t, i) => { tops[i]._ord = getText(t.properties?.['Reihenfolge']) || 0; });
tops.sort((a, b) => a._ord - b._ord).forEach(t => delete t._ord);

if (tops.length === 0) {
  console.warn('WARN: Keine finalen TOPs gefunden – Dokument wird trotzdem erzeugt.');
}

// ── Nächste Termine parsen ─────────────────────────────────────────
function parseNaechsteTermine(raw) {
  if (!raw) return [];
  return raw.split('\n').map(l => l.trim()).filter(Boolean).map(line => {
    const [datum, ort] = line.split('|').map(s => s.trim());
    return { termin_datum: datum || line, termin_ort_oder_leer: ort || '______________________' };
  });
}

// ── Finaler Payload ────────────────────────────────────────────────
const payload = {
  termin:           termin_str,
  ort_name:         termin_data.ort_name,
  ort_adresse:      termin_data.ort_adresse,
  mitglieder,
  gast_name:        termin_data.gast_name,
  gast_web:         termin_data.gast_web,
  gastvortrag_name: termin_data.gastvortrag_name,
  gastvortrag_web:  termin_data.gastvortrag_web,
  tops,
  themenvorschau:   termin_data.themenvorschau,
  naechste_termine: parseNaechsteTermine(termin_data.naechste_termine_raw),
};

const payload_json = JSON.stringify(payload);
const output_path  = `/opt/scripts/output/AGD_${datei_datum}_Boardmeeting.docx`;

return [{
  json: {
    payload,
    payload_json,
    datei_datum,
    page_id: termin_data.page_id,
    output_path,
    termin: termin_str,
    // E-Mail-Empfänger optional aus Webhook-Body übernehmen
    email_to:   $('Webhook: Agenda anfordern').first()?.json?.body?.email_to || '',
    send_email: $('Webhook: Agenda anfordern').first()?.json?.body?.send_email === true,
  }
}];

// Agenda als .docx direkt im Code-Node erzeugen (ersetzt Execute Command).
// ── Voraussetzungen in der n8n-Umgebung ──────────────────────────────
//   NODE_FUNCTION_ALLOW_BUILTIN=fs,path           (oder *)
//   NODE_FUNCTION_ALLOW_EXTERNAL=pizzip,docxtemplater   (oder *)
//   pizzip + docxtemplater installiert unter MODULES_DIR (/opt/scripts/node_modules)
const fs   = require('fs');
const path = require('path');

const SCRIPTS_DIR   = '/opt/scripts';
const MODULES_DIR   = SCRIPTS_DIR + '/node_modules';
const TEMPLATE_PATH = SCRIPTS_DIR + '/agenda_template.docx';

// Modul laden: erst per Name (falls im n8n-Image installiert), sonst per absolutem Pfad
function load(name) {
  try { return require(name); }
  catch (e) { return require(MODULES_DIR + '/' + name); }
}
let PizZip, Docxtemplater;
try {
  PizZip        = load('pizzip');
  Docxtemplater = load('docxtemplater');
} catch (e) {
  throw new Error('Module nicht ladbar (pizzip/docxtemplater). ' +
    'NODE_FUNCTION_ALLOW_EXTERNAL setzen und Packages unter ' + MODULES_DIR + ' installieren. Detail: ' + e.message);
}

const item = $input.first().json;
const data = item.payload;
const outputPath = item.output_path;

let buf;
try {
  const content = fs.readFileSync(TEMPLATE_PATH, 'binary');
  const zip = new PizZip(content);
  const doc = new Docxtemplater(zip, { paragraphLoop: true, linebreaks: true, nullGetter: () => '' });
  doc.render(data);
  buf = doc.getZip().generate({ type: 'nodebuffer', compression: 'DEFLATE' });
} catch (e) {
  throw new Error('Agenda-Generierung fehlgeschlagen: ' + (e.message || e));
}

// Datei auf den Server schreiben (für "Agenda Link" in Notion)
fs.writeFileSync(outputPath, buf);

// Binary direkt mitliefern, falls später ohne erneutes Lesen gebraucht
const binaryData = await this.helpers.prepareBinaryData(
  buf,
  path.basename(outputPath),
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
);

return [{
  json: { ...item, filepath: outputPath },
  binary: { data: binaryData },
}];
